def gen(rng, size):
    n = max(3, min(size, 40))
    nums = [rng.randint(1, 30) for _ in range(n)]
    edges = []
    for v in range(1, n):
        u = rng.randint(0, v - 1)
        edges.append([u, v])
    rng.shuffle(edges)
    for e in edges:
        if rng.random() < 0.5:
            e.reverse()
    return [nums, edges]

