class Solution:
    def minimumScore(self, nums, edges):
        n = len(nums)
        adj = [[] for _ in range(n)]
        elist = [(a, b) for a, b in edges]
        for a, b in elist:
            adj[a].append(b)
            adj[b].append(a)
        m = len(elist)
        best = float('inf')
        # brute: remove every pair of edges, find 3 components, XOR each
        for i in range(m):
            for j in range(i + 1, m):
                blocked = {i, j}
                comp = [-1] * n
                cid = 0
                for start in range(n):
                    if comp[start] != -1:
                        continue
                    stack = [start]
                    comp[start] = cid
                    while stack:
                        u = stack.pop()
                        for k, (a, b) in enumerate(elist):
                            if k in blocked:
                                continue
                            if a == u and comp[b] == -1:
                                comp[b] = cid
                                stack.append(b)
                            elif b == u and comp[a] == -1:
                                comp[a] = cid
                                stack.append(a)
                    cid += 1
                if cid != 3:
                    continue
                xors = [0, 0, 0]
                for v in range(n):
                    xors[comp[v]] ^= nums[v]
                best = min(best, max(xors) - min(xors))
        return best

