var minimumScore = function(nums, edges) {
    const n = nums.length;
    const adj = Array.from({length: n}, () => []);
    for (const [a, b] of edges) { adj[a].push(b); adj[b].push(a); }
    let total = 0;
    for (const v of nums) total ^= v;
    const sub = new Array(n).fill(0);
    const tin = new Array(n).fill(0);
    const tout = new Array(n).fill(0);
    const parent = new Array(n).fill(-1);
    const visited = new Array(n).fill(false);
    let timer = 0;
    const stack = [[0, false]];
    while (stack.length) {
        const [node, processed] = stack.pop();
        if (processed) {
            tout[node] = timer++;
            let s = nums[node];
            for (const c of adj[node]) if (c !== parent[node]) s ^= sub[c];
            sub[node] = s;
            continue;
        }
        if (visited[node]) continue;
        visited[node] = true;
        tin[node] = timer++;
        stack.push([node, true]);
        for (const c of adj[node]) {
            if (c !== parent[node]) {
                parent[c] = node;
                stack.push([c, false]);
            }
        }
    }
    const isAnc = (u, v) => tin[u] <= tin[v] && tout[v] <= tout[u];
    let best = Infinity;
    for (let a = 1; a < n; a++) {
        for (let b = a + 1; b < n; b++) {
            let x1, x2, x3;
            if (isAnc(a, b)) {
                x1 = sub[b]; x2 = sub[a] ^ sub[b]; x3 = total ^ sub[a];
            } else if (isAnc(b, a)) {
                x1 = sub[a]; x2 = sub[b] ^ sub[a]; x3 = total ^ sub[b];
            } else {
                x1 = sub[a]; x2 = sub[b]; x3 = total ^ sub[a] ^ sub[b];
            }
            const mx = Math.max(x1, x2, x3), mn = Math.min(x1, x2, x3);
            best = Math.min(best, mx - mn);
        }
    }
    return best;
};
